### Middleware Responding Sets Transaction Name (Node.js)

Source: https://github.com/newrelic/node-newrelic/blob/main/documentation/transaction-naming-philosophy.md

This example illustrates how a middleware function that sends a response takes precedence in determining the transaction name. If multiple middleware functions are involved, the one that ultimately calls `res.send()` or a similar response method will define the transaction's name, overriding any previous naming attempts.

```javascript
const newrelic = require('newrelic');
const express = require('express');

const app = express();

app.get('/beep', function(req, res, next) {
  res.respondWith = 'boop';
  next();
});

app.get('/ping', function(req, res, next) {
  res.respondWith = 'pong';
  next();
});

app.use('/:wat', function(req, res, next) {
  // All responses come from this middleware.
  res.send(res.respondWith);
});

app.listen(8080);
```

